function Invoke-PacmanBar { [CmdletBinding()] param([switch]$NoKeepAlive); $totalSteps = 32; $pingEvery = 60; $esc = [char]27; $pac = [char]0x15E7; $ghost = [char]0x15E3; $dot = [char]0x00B7; $ghostCol = @("$esc[91m", "$esc[95m", "$esc[96m", "$esc[38;5;208m"); $pacCol = "$esc[93m"; $dotCol = "$esc[38;5;223m"; $wshell = if (-not $NoKeepAlive) { New-Object -ComObject WScript.Shell } else { $null }; $lastPing = Get-Date; [Console]::CursorVisible = $false; Write-Host ''; try { while ($true) { for ($i = 0; $i -le $totalSteps; $i++) { $eaten = ' ' * $i; $sb = ''; $gi = 0; for ($d = 0; $d -lt ($totalSteps - $i); $d++) { if ($d % 3 -eq 0) { $sb += $ghostCol[$gi % 4] + [string]$ghost + ' '; $gi++ } else { $sb += $dotCol + [string]$dot + ' ' } }; $mouth = if ($i % 2 -eq 0) { [string]$pac } else { 'c' }; $bar = "$esc[2K`r$esc[0m[ $eaten$pacCol$mouth $sb$esc[0m]"; Write-Host $bar -NoNewline; if (-not $NoKeepAlive -and ((Get-Date) - $lastPing).TotalSeconds -ge $pingEvery) { if (Get-Process -Name 'ms-teams','Teams' -ErrorAction SilentlyContinue) { $wshell.SendKeys('{SCROLLLOCK}'); Start-Sleep -Milliseconds 80; $wshell.SendKeys('{SCROLLLOCK}') }; $lastPing = Get-Date }; Start-Sleep -Milliseconds 100 } } } finally { [Console]::CursorVisible = $true; Write-Host "`n$esc[0mPac-Man stopped." } }
